SELECT t.topic_id, v.item_type, v.prompt, v.model_answer, v.points, v.source_exam, v.difficulty, v.estimated_time_sec
FROM (VALUES

-- ===== DMZ + FIREWALL =====
('dmz-firewall', 'blurt', 'Schreibe alles was du über DMZ und Firewall-Konzepte weißt: Zweck, einstufiges vs zweistufiges Konzept, typische Server in DMZ, Paketfilter vs Application-Gateway.', 'DMZ (Demilitarisierte Zone): Subnetz zwischen externem (Internet) und internem Netz. Enthält öffentlich zugängliche Server (Web, Mail, DNS, VPN) — isoliert vom internen LAN. Zweck: Angreifer auf DMZ-Server bekommt keinen direkten Zugriff auf internes Netz.\n\nEinstufig: 1 Firewall mit 3 Interfaces (extern/DMZ/intern). Einfach, günstig, aber Single Point of Failure.\n\nZweistufig: 2 Firewalls — Firewall 1 zwischen Internet und DMZ, Firewall 2 zwischen DMZ und internem Netz. Besser: bei Kompromittierung der ersten Firewall immer noch Schutz durch zweite. Empfohlen: unterschiedliche Hersteller (Diversität → andere Schwachstellen).\n\nServer in DMZ: Web-Server, Mail-Relay, DNS, VPN-Gateway, Proxy, Reverse-Proxy.\n\nFirewall-Typen: Paketfilter (Layer 3/4, schnell), Stateful (trackt Sessions), Application-Gateway (Layer 7, Deep Packet Inspection, langsamer aber sicherer).', 12, 'ki-generated', 4, 480),
('dmz-firewall', 'cued', 'Warum wird bei zweistufigem Firewall-Konzept empfohlen zwei UNTERSCHIEDLICHE Hersteller einzusetzen?', 'Diversität reduziert Angriffsoberfläche: ein Zero-Day-Exploit für Firewall-Hersteller A kompromittiert nur die eine Firewall — die zweite (von Hersteller B) hat andere Schwachstellen und bleibt intakt. Wäre beide von gleichem Hersteller, könnte ein einziger Exploit beide umgehen.', 3, 'ki-generated', 3, 120),
('dmz-firewall', 'application', 'Dein Unternehmen hat 100 MA, nutzt Web-Shop, Mail-Server, internen Fileserver + DB. Entwirf ein zweistufiges Firewall-Konzept: Welche Server in DMZ, welche Firewalls, welche Zugriffsregeln.', 'Topologie:\nINTERNET ← Firewall1 (Hersteller A) → DMZ → Firewall2 (Hersteller B) → Internes LAN\n\nIn DMZ:\n- Reverse-Proxy (terminiert HTTPS, leitet weiter an intern. Web-App)\n- Mail-Relay (eingehend SMTP, leitet weiter intern)\n- DNS-Resolver extern\n- VPN-Gateway\n\nIntern (geschützt): App-Server, Datenbank, File-Server, Domain-Controller, Mitarbeiter-Clients.\n\nRegeln Firewall 1 (Internet → DMZ):\n- TCP 443 → Reverse-Proxy\n- TCP 25 → Mail-Relay\n- UDP/TCP 53 → DNS\n- UDP 500/4500 (IPsec) → VPN-Gateway\n- ALLES andere: DROP.\n\nRegeln Firewall 2 (DMZ → Intern):\n- Reverse-Proxy → App-Server TCP 8080\n- Mail-Relay → Internal-Mail TCP 25\n- VPN → Intern (wird zum internen IP-Raum geroutet, durch Access-Policies eingeschränkt)\n- DROP alles andere.\n\nRegeln Firewall 2 (Intern → DMZ): nur gezielt für Admin (SSH auf 22 von Admin-Subnetz).', 10, 'ki-generated', 5, 720),

-- ===== VLAN =====
('vlan', 'blurt', 'Schreibe alles was du über VLAN weißt: Zweck, 802.1Q-Tagging, Trunk vs Access Port, VLAN-Typen (Default/Native/Voice/Management/Data), Inter-VLAN-Routing.', 'VLAN (Virtual LAN, IEEE 802.1Q): logische Netzwerk-Segmentierung auf Layer 2. Trennt Broadcast-Domänen OHNE physische Trennung.\n\nZweck: Sicherheit (Buchhaltung-VLAN isoliert von Gäste-VLAN), Performance (weniger Broadcasts), Flexibilität (MA wechselt Abteilung ohne Umkabeln).\n\n802.1Q-Tag: 4-Byte-Header im Ethernet-Frame, enthält VLAN-ID (1-4094). VID 0 + 4095 reserviert. Max 4094 VLANs pro Switch.\n\nPort-Typen:\n- Access-Port: untagged Traffic eines VLAN (Endgeräte).\n- Trunk-Port: tagged Traffic mehrerer VLANs (Switch-zu-Switch, Router-on-a-Stick).\n\nVLAN-Arten:\n- Default VLAN 1: standardmäßig, sollte NICHT produktiv genutzt werden (Sicherheit).\n- Native VLAN: untagged Traffic auf Trunk-Port (Standard: VLAN 1).\n- Voice VLAN: VoIP-Telefone (QoS-Priorisierung).\n- Management VLAN: Administration der Netzwerkgeräte (separat von User-Traffic).\n- Data VLAN: normale PCs / User-Traffic.\n\nInter-VLAN-Routing: Layer-3-Switch oder Router (Router-on-a-Stick mit Sub-Interfaces pro VLAN).', 11, 'ki-generated', 4, 480),
('vlan', 'cued', 'Was passiert wenn ein Ethernet-Frame ohne 802.1Q-Tag über einen Trunk-Port eingeht?', 'Der Frame wird dem NATIVE VLAN zugeordnet (standardmäßig VLAN 1, sollte aus Sicherheitsgründen geändert werden auf ein dediziertes Native-VLAN). Alle untagged Frames auf einem Trunk gehören zum Native VLAN. Frames im Native VLAN werden auf dem Trunk ausgehend OHNE Tag verschickt — dadurch mögliche "VLAN-Hopping"-Angriffe (Angreifer markiert Frame mit fremdem VLAN-Tag).', 3, 'ki-generated', 3, 150),
('vlan', 'application', 'Plane die VLAN-Struktur für ein Büro mit 4 Abteilungen: Geschäftsführung (5 PCs), Buchhaltung (10 PCs, sensible Daten), Entwicklung (20 PCs), Gäste-WLAN. Plus Voice-Telefone und Server. Gib VLAN-IDs, Subnetze und Inter-VLAN-Regeln an.', 'VLAN-Design:\n- VLAN 1:  Default (ungenutzt, nur temporär bei Setup).\n- VLAN 10: Management — 192.168.10.0/24 (Switches, APs, Firewall-Admin).\n- VLAN 20: Geschäftsführung — 192.168.20.0/27 (Access zu allem).\n- VLAN 30: Buchhaltung — 192.168.30.0/27 (Zugriff nur auf ERP-Server, kein Internet außer Bank).\n- VLAN 40: Entwicklung — 192.168.40.0/26 (volle Internet, Zugriff Git-Server).\n- VLAN 50: Server — 192.168.50.0/26 (File, App, ERP, DB).\n- VLAN 60: Voice — 192.168.60.0/24 (VoIP-Telefone, QoS höher).\n- VLAN 99: Gäste-WLAN — 10.99.0.0/24 (nur Internet, keine Interna).\n\nTrunk-Ports: Switch-Switch-Verbindungen + zum Router.\n\nInter-VLAN-Regeln (Firewall/Router ACL):\n- Buchhaltung → ERP-Server TCP 1433 ALLOW, Rest DROP.\n- Entwicklung → Server TCP 443, 22, 5432 ALLOW.\n- Gäste → Internet ALLOW, Interna DROP.\n- Management-VLAN → alle Geräte ALLOW (Admin).\n- Voice → SIP-Server + Internet (Telefonie) ALLOW.', 8, 'ki-generated', 4, 600),

-- ===== SQL-QUERIES =====
('sql-queries', 'blurt', 'Schreibe alles was du über SQL weißt: DDL (CREATE, ALTER, DROP), DML (INSERT, UPDATE, DELETE, SELECT), JOIN-Arten, Aggregatfunktionen, GROUP BY / HAVING, Subqueries, Normalisierung (1-3 NF + Anomalien).', 'DDL (Data Definition): CREATE TABLE, ALTER TABLE (ADD/DROP COLUMN), DROP TABLE, CREATE INDEX.\n\nDML (Data Manipulation): INSERT INTO, UPDATE SET WHERE, DELETE FROM WHERE, SELECT FROM WHERE.\n\nSELECT-Syntax: SELECT columns FROM table [JOIN ...] [WHERE condition] [GROUP BY] [HAVING] [ORDER BY] [LIMIT n].\n\nJOIN-Arten:\n- INNER JOIN: nur Zeilen mit Match in beiden Tabellen.\n- LEFT JOIN: alle Zeilen links + passende rechts (NULL falls keine).\n- RIGHT JOIN: wie LEFT, umgekehrt.\n- FULL OUTER JOIN: alle Zeilen beider Seiten.\n\nAggregatfunktionen: COUNT(*), SUM(col), AVG(col), MIN, MAX. Immer mit GROUP BY bei gemischten Spalten.\n\nWHERE vs HAVING: WHERE filtert Zeilen VOR Aggregation, HAVING nach (für Aggregat-Bedingungen).\n\nSubqueries: Unterabfrage in WHERE (WHERE id IN (SELECT ...)), FROM (temporäre Tabelle), SELECT (Skalar).\n\nNormalisierung:\n- 1. NF: atomare Werte (keine Listen in einer Zelle).\n- 2. NF: 1. NF + jeder Nicht-Schlüssel vollständig vom Primärschlüssel abhängig.\n- 3. NF: 2. NF + keine transitiven Abhängigkeiten (Nicht-Schlüssel → Nicht-Schlüssel verboten).\n\nAnomalien nicht-normalisierter DBs: Einfüge-Anomalie, Lösch-Anomalie, Update-Anomalie (redundante Daten müssen überall geändert werden).', 15, 'ki-generated', 4, 540),
('sql-queries', 'cued', 'Schreibe ein SELECT-Statement: alle Kunden die zwischen Januar und März 2026 bestellt haben, sortiert nach Name, jeder Kunde nur einmal.', 'SELECT DISTINCT k.name\nFROM Kunden k\nJOIN Bestellungen b ON k.kunden_id = b.kunden_id\nWHERE b.bestelldatum >= ''2026-01-01''\n  AND b.bestelldatum <= ''2026-03-31''\nORDER BY k.name;', 4, 'ki-generated', 3, 180),
('sql-queries', 'cued', 'Was ist der Unterschied zwischen WHERE und HAVING? Zeige ein Beispiel.', 'WHERE filtert EINZELNE ZEILEN vor dem Gruppieren. HAVING filtert GRUPPEN nach dem Gruppieren (für Bedingungen auf Aggregatfunktionen).\n\nBeispiel: Alle Kunden mit mehr als 5 Bestellungen im Jahr 2026:\n\nSELECT k.name, COUNT(*) AS anzahl\nFROM Kunden k JOIN Bestellungen b ON k.kunden_id = b.kunden_id\nWHERE b.bestelldatum >= ''2026-01-01''   -- einzelne Zeile filtern\nGROUP BY k.name\nHAVING COUNT(*) > 5;                     -- Aggregat filtern', 4, 'ki-generated', 4, 240),
('sql-queries', 'application', 'Tabelle Bestellung(BestellID, KundenID, Datum, Gesamt). Schreibe SQL: (a) Top-5 Kunden nach Gesamtumsatz 2025, (b) Monatlicher Umsatz für 2025, (c) Lösche alle Bestellungen älter als 5 Jahre.', '(a) Top-5 Kunden nach Umsatz 2025:\nSELECT k.name, SUM(b.gesamt) AS umsatz\nFROM Kunden k JOIN Bestellung b ON k.kunden_id = b.kunden_id\nWHERE b.datum BETWEEN ''2025-01-01'' AND ''2025-12-31''\nGROUP BY k.kunden_id, k.name\nORDER BY umsatz DESC\nLIMIT 5;\n\n(b) Monatsumsätze 2025:\nSELECT EXTRACT(MONTH FROM datum) AS monat,\n       SUM(gesamt) AS umsatz\nFROM Bestellung\nWHERE datum BETWEEN ''2025-01-01'' AND ''2025-12-31''\nGROUP BY EXTRACT(MONTH FROM datum)\nORDER BY monat;\n\n(c) Lösche Bestellungen älter als 5 Jahre:\nDELETE FROM Bestellung\nWHERE datum < NOW() - INTERVAL ''5 years'';', 10, 'ki-generated', 4, 600),

-- ===== VPN + VERSCHLÜSSELUNG =====
('vpn-verschluesselung', 'blurt', 'Schreibe alles was du über VPN und Verschlüsselung weißt: VPN-Arten (Site-to-Site/Remote), IPsec Tunnel vs Transport, sym/asym/hybride Verschlüsselung, TLS/SSL, Authentizität/Integrität/Vertraulichkeit.', 'VPN (Virtual Private Network): verschlüsselte Verbindung über öffentliches Netz (Internet).\n\nVPN-Arten:\n- Site-to-Site: 2 Standorte verbunden (Firmen-Router zu Router).\n- End-to-Site (Remote-Access): Einzel-Client zu Firmennetz (Mitarbeiter Home-Office).\n- End-to-End: Client zu Client direkt.\n\nIPsec (wichtigstes VPN-Protokoll):\n- Transport-Modus: nur Payload verschlüsselt, IP-Header original. Zwischen 2 Hosts (End-to-End).\n- Tunnel-Modus: kompletter IP-Paket verschlüsselt + in neuen IP-Header gekapselt. Standard für Site-to-Site.\n\nVerschlüsselungsarten:\n- Symmetrisch: EIN Schlüssel für ver- + entschlüsseln (AES, 3DES). Schnell aber Schlüsselaustausch-Problem.\n- Asymmetrisch: Schlüsselpaar (public/private, RSA, ECC). Sicher aber langsam.\n- Hybrid: Session-Key symmetrisch, via asym. Verschlüsselung übertragen. TLS/SSL funktioniert so.\n\n3 Schutzziele:\n1. Vertraulichkeit (Confidentiality): Daten nur für Berechtigte lesbar. Erreicht durch Verschlüsselung.\n2. Integrität (Integrity): Daten unverändert. Erreicht durch Hash (SHA-256) + MAC/HMAC.\n3. Authentizität (Authenticity): Absender eindeutig identifiziert. Erreicht durch digitale Signaturen / Zertifikate.\n\nTLS/SSL: Standard für HTTPS — kombiniert asym. Handshake + sym. Datenübertragung + Zertifikate (X.509, signiert durch CA).', 14, 'ki-generated', 4, 600),
('vpn-verschluesselung', 'cued', 'Erkläre das Prinzip der hybriden Verschlüsselung anhand von HTTPS.', 'HTTPS nutzt hybride Verschlüsselung:\n\n1. Client + Server tauschen ASYMMETRISCH einen Session-Key aus (TLS-Handshake mit Diffie-Hellman + RSA/ECC).\n2. Server schickt sein Zertifikat — Client prüft es bei CA.\n3. Beide Seiten haben jetzt den Session-Key.\n4. Die eigentliche Datenübertragung läuft SYMMETRISCH (AES-256-GCM) — viel schneller.\n\nVorteil: Sicherer Schlüsselaustausch (asym.) + performante Übertragung (sym.).', 3, 'ki-generated', 3, 180),
('vpn-verschluesselung', 'application', 'Erkläre die 3 Schutzziele (CIA-Triade) anhand eines VPN-Beispiels: Außendienst-Mitarbeiter nutzt Firmen-VPN.', 'CIA-Triade im VPN-Szenario:\n\n1. VERTRAULICHKEIT (Confidentiality):\nDer Außendienstler schickt Kundendaten übers öffentliche Internet. Ohne VPN könnten Angreifer im WLAN oder auf Zwischen-Routern mitlesen.\nUmsetzung: IPsec verschlüsselt die Payload mit AES-256. Ohne Session-Key sehen Angreifer nur Zufallsbytes.\n\n2. INTEGRITÄT (Integrity):\nEin Angreifer könnte Pakete manipulieren (z.B. Überweisungsdaten ändern).\nUmsetzung: IPsec hängt an jedes Paket einen HMAC-SHA256-Hash. Der Empfänger prüft den Hash — stimmt er nicht, wird das Paket verworfen.\n\n3. AUTHENTIZITÄT (Authenticity):\nWie kann der Außendienstler sicher sein dass er tatsächlich mit dem echten Firmen-VPN-Gateway verbunden ist und nicht mit einem Fake?\nUmsetzung: IPsec nutzt Zertifikate (X.509) oder Pre-Shared Keys. Beide Seiten weisen beim Handshake ihre Identität nach. Nur dann wird der Tunnel aufgebaut.\n\nAlle 3 Ziele werden durch IPsec gleichzeitig erfüllt. Das ist die typische Anforderung "Das VPN muss Authentizität, Integrität und Vertraulichkeit gewährleisten".', 10, 'ki-generated', 4, 600),

-- ===== WLAN =====
('wlan', 'blurt', 'Schreibe alles was du über WLAN weißt: Standards (802.11a/b/g/n/ac/ax/be), Frequenzbänder 2,4 vs 5 GHz, WPA2/WPA3, WPA-PSK vs Enterprise, Access Points, Kanalüberlappung.', 'WLAN-Standards (IEEE 802.11):\n- 802.11a: 5 GHz, 54 Mbit/s (alt).\n- 802.11b: 2,4 GHz, 11 Mbit/s.\n- 802.11g: 2,4 GHz, 54 Mbit/s.\n- 802.11n (Wi-Fi 4): 2,4 + 5 GHz, 600 Mbit/s, MIMO.\n- 802.11ac (Wi-Fi 5): 5 GHz, 6,9 Gbit/s, MU-MIMO.\n- 802.11ax (Wi-Fi 6 / 6E): 2,4/5/6 GHz, 9,6 Gbit/s, OFDMA, bessere Effizienz bei vielen Clients.\n- 802.11be (Wi-Fi 7): 2024, bis 46 Gbit/s, 320 MHz Kanäle.\n\nFrequenzbänder:\n- 2,4 GHz: Reichweite hoch, Geschwindigkeit niedrig, viele Störungen (Mikrowelle, Bluetooth, Nachbarn). Kanäle 1, 6, 11 überlappen nicht.\n- 5 GHz: Reichweite geringer (kürzere Wellenlänge), Geschwindigkeit hoch, weniger Störungen, mehr Kanäle.\n- 6 GHz (Wi-Fi 6E): sehr wenig Konflikt, noch mehr Kanäle.\n\nVerschlüsselung:\n- WEP: unsicher (geknackt).\n- WPA: veraltet.\n- WPA2: verbreitet, AES (CCMP).\n- WPA3: aktueller, Forward Secrecy, Schutz gegen Offline-Brute-Force.\n\nAuthentifizierung:\n- PSK (Pre-Shared Key): gemeinsames Passwort, passend für Heim/Klein.\n- Enterprise (802.1X + RADIUS): pro User eigene Credentials, Zertifikate möglich, empfohlen für Firma.\n\nAccess Points: zentrale Funkverwaltung, PoE-Versorgung (802.3af/at/bt), Mesh möglich, Controller-basiert (Cisco WLC, UniFi).', 13, 'ki-generated', 4, 480),
('wlan', 'cued', 'Warum sollte man im Unternehmen WPA3-Enterprise statt WPA2-PSK verwenden?', 'WPA3-Enterprise bietet:\n1. Pro-User-Credentials: Jeder MA hat eigenes Login (802.1X + RADIUS). Bei Mitarbeiter-Wechsel muss nur EIN Konto gesperrt werden, nicht das globale PSK geändert + an alle verteilt.\n2. Forward Secrecy: vergangener Traffic bleibt sicher, selbst wenn ein Schlüssel kompromittiert wird.\n3. Schutz gegen Offline-Brute-Force (Dragonfly-Handshake).\n4. Zertifikate möglich (EAP-TLS): noch sicherer als Passwort.\n\nWPA2-PSK hat EIN Passwort für alle → Compliance-Problem, bei Kündigung müsste PSK global rotiert werden.', 3, 'ki-generated', 4, 180),
('wlan', 'application', 'Ein Unternehmen benötigt WLAN für: Mitarbeiter (80 MA, sensible Daten), Gäste (bis 50 parallel), IoT-Geräte (Drucker, Kameras). Plane WLAN-Design: Access Points, SSIDs, Verschlüsselung, VLAN-Trennung.', 'WLAN-Design:\n\nAccess Points:\n- Wi-Fi 6 (802.11ax) Controller-basierte APs (Cisco, UniFi, Aruba).\n- Dichte: 1 AP pro 40-60 m² in Büro, Richtwert 20-30 Clients pro AP.\n- Für 80 MA + 50 Gäste + IoT = ca. 130 Clients → 4-6 APs, PoE-versorgt.\n\n3 SSIDs (auf gleichen APs, getrennte VLANs):\n1. "Corp-Secure" — WPA3-Enterprise mit RADIUS-Server, Authentifizierung über AD. VLAN 20 (internes Netz). 802.1X.\n2. "Guest-WiFi" — WPA2-PSK mit wöchentlich wechselndem Passwort ODER captive portal. VLAN 99 (nur Internet, keine Interna). Zeitlimit 4h.\n3. "IoT-Net" — WPA2-PSK (manche IoT unterstützen nur WPA2). VLAN 30 (isoliert, keine Internet-Zugriff außer spezifische Endpoints).\n\nWeitere Sicherheits-Maßnahmen:\n- MAC-Filter für IoT (nur registrierte Geräte).\n- Gast-Netz isoliert vom Corp- und IoT-Netz.\n- Intrusion Detection am WLAN-Controller.\n- Regelmäßige Firmware-Updates.\n- Monitoring der verbundenen Clients.\n\nFrequenz-Planung: Nachbar-APs auf nicht-überlappenden Kanälen (1/6/11 im 2,4-GHz, automatisch im 5-GHz).', 10, 'ki-generated', 4, 720),

-- ===== RECHTSFORMEN =====
('rechtsformen', 'blurt', 'Schreibe alles über GmbH, Einzelunternehmen, UG und AG — Gründung, Kapital, Haftung, Organe, Steuern, Publikationspflicht.', 'Einzelunternehmen:\nGründung: einfach, Gewerbeanmeldung beim Gewerbeamt. Mind.-Kapital: 0 €. Haftung: UNBESCHRÄNKT mit gesamten Privatvermögen. Organe: nur der Inhaber. Steuern: Einkommensteuer auf Gewinn. Handelsregister-Eintragung bei Istkaufmann-Kriterien.\n\nUG (haftungsbeschränkt / "Mini-GmbH"):\nGründung: Notar, Handelsregister. Mind.-Kapital: 1 €. Haftung: BESCHRÄNKT auf Gesellschaftsvermögen. Zwangsrücklage 25 % des Gewinns bis zum Erreichen von 25.000 € (dann Upgrade zur GmbH möglich). Organe: Geschäftsführer + Gesellschafter.\n\nGmbH:\nGründung: Notar, Handelsregister. Mind.-Stammkapital: 25.000 € (12.500 € müssen bei Gründung eingezahlt sein). Haftung: BESCHRÄNKT auf Stammkapital. Organe: Geschäftsführer, Gesellschafterversammlung. Steuern: Körperschaftsteuer + Gewerbesteuer + Ausschüttungen werden beim Gesellschafter mit Abgeltungssteuer 25 % belegt. Jahresabschluss ist publizitätspflichtig (Bundesanzeiger).\n\nAG:\nGründung: komplex, mind. 1 Person, Notar. Mind.-Grundkapital: 50.000 €. Haftung: BESCHRÄNKT auf Aktienkapital. Organe: Vorstand, Aufsichtsrat (min. 3 Personen), Hauptversammlung. Aktien handelbar. Für Mittelstand selten (nur bei geplantem Börsengang).\n\nJuristische Person vs natürliche: GmbH/UG/AG = juristisch (eigene Rechtspersönlichkeit, eigener Name, eigenes Vermögen). Einzelunternehmen = natürlich (Inhaber handelt persönlich).', 10, 'ki-generated', 4, 600),
('rechtsformen', 'cued', 'Warum ist die GmbH für mittelständische IT-Unternehmen besonders beliebt?', 'Gründe:\n1. Haftungsbeschränkung: Das Privatvermögen der Gesellschafter ist geschützt — bei Insolvenz haftet nur das Stammkapital (25.000 €).\n2. Juristische Person: GmbH kann Verträge, Klagen, Besitz eigenständig — unabhängig von den Gesellschaftern.\n3. Kontinuität: GmbH besteht weiter wenn Gesellschafter wechseln (Anteilsübertragung möglich).\n4. Kapitalbeschaffung: Anteile können an Investoren verkauft werden.\n5. Steuerlich vorteilhaft bei Gewinn-Thesaurierung (Körperschaftsteuer 15 % statt Einkommensteuer bis 45 %).\n6. Professionelles Image für Kunden.\n\nNachteil: Gründungskosten (Notar, HR, Stammkapital), komplexere Buchführung (Bilanz statt EÜR), Publizitätspflicht.', 3, 'ki-generated', 3, 180),
('rechtsformen', 'application', 'Vergleiche GmbH und Einzelunternehmen für ein 3-Personen-IT-Startup das 30.000 € Gewinn pro Jahr erwartet. Welche Form, warum, was muss bedacht werden?', 'Empfehlung: GmbH (oder evtl. UG als "Light"-Version).\n\nHaftung:\n- Einzelunternehmen: 3 Personen könnten nicht gemeinsam gründen (nur 1 Inhaber). Alternativ GbR — aber auch dort volle persönliche Haftung aller mit Privatvermögen.\n- GmbH: Haftung auf 25.000 € Stammkapital beschränkt. Bei Bug → Kundenschaden → Privatvermögen geschützt.\n\nSteuerlich bei 30.000 € Gewinn (geteilt durch 3 = 10.000 € pro Person):\n- GbR/Einzel: Einkommensteuer nach Tarif. 10.000 € liegen unter Grundfreibetrag (2026: ~11.600 €) → FAST keine Steuer. Aber: bei steigendem Gewinn progressiv bis 45 %.\n- GmbH: Körperschaftsteuer 15 % + Solidaritätszuschlag 5,5 % + Gewerbesteuer (je nach Gemeinde 7-17 %). Gesamt ca. 30 %. Ausschüttung: zusätzlich Abgeltungssteuer 25 % auf Dividenden.\n\nBei 30.000 €: Einzelunternehmen steuerlich besser. Aber Haftung schlägt das.\n\nWichtige Aspekte:\n1. Stammkapital: 25.000 € aufbringen (oder UG mit 1 €, aber Rücklagepflicht bis 25.000 €).\n2. Notar- + HR-Kosten ca. 1.000-1.500 € bei Gründung.\n3. Buchführung: Bilanzierung statt EÜR — Steuerberater empfohlen.\n4. Geschäftsführer-Vertrag nötig (kann einer von den 3 sein, ggf. angestellt).\n5. Gesellschaftsvertrag: Regelung Stimmrechte, Gewinnverteilung, Austritt.\n6. Mindestens einmal jährlich Gesellschafterversammlung.\n\nFazit: GmbH trotz höherer Steuer-Komplexität sinnvoll wegen Haftungsbegrenzung im Software-Geschäft (Datenpannen, Lizenz-Verstöße etc. können teuer werden).', 10, 'ki-generated', 5, 900),

-- ===== EKK VERSCHIEBUNG: WEITERE TOPICS (kompakter) =====
('organigramm', 'blurt', 'Schreibe alles was du über Organigramme weißt: Linienorganisation, Stab-Linien, Matrix-Organisation, Spartenorganisation, Vor/Nachteile, Vollmachten (ppa., i.V.).', 'Organigramm: grafische Darstellung der betrieblichen Aufbauorganisation.\n\nArten:\n1. Linienorganisation: klare Hierarchie, jede Stelle einem Vorgesetzten unterstellt. Einfach, aber lang, Weg für Kommunikation.\n2. Stab-Linien-Organisation: Linienorganisation + Stabstellen (beraten ohne Weisungsrecht). Typische Stabstellen: Rechtsabteilung, Assistenz der Geschäftsführung. Vorteil: Entlastung Vorgesetzte. Nachteil: Konflikte zwischen Linie und Stab.\n3. Matrix-Organisation: zwei Dimensionen gleichzeitig (z.B. Fachbereich × Projekt). Jede Stelle hat ZWEI Vorgesetzte. Vorteil: Flexibilität, Spezialisten pro Projekt. Nachteil: Weisungskonflikte.\n4. Spartenorganisation: nach Produkten/Regionen. Pro Sparte eigener Vorstand, komplette Wertschöpfung. Gut für Konzerne.\n\nVollmachten (HGB):\n- Prokura (ppa. = "per procura autoritate"): umfassende Handlungsvollmacht, Eintragung ins Handelsregister. Kann alle Geschäfte, außer Grundstücksverkauf und Prokura selbst erteilen. Nicht übertragbar.\n- Handlungsvollmacht (i.V. = "in Vertretung"): begrenzter Umfang, keine HR-Eintragung, kann übertragen werden mit Zustimmung.\n- Einzelvollmacht: für einzelne Geschäfte.', 8, 'ki-generated', 3, 420),
('organigramm', 'application', 'Erstelle Organigramm für IT-GmbH mit: Geschäftsführer (Müller), Assistenz (Schmidt), 3 Abteilungen: Entwicklung (Leiter Weber + 15 MA), Support (Leiter Klein + 5 MA), Vertrieb (Leiter Huber + 3 MA). Ausbilder Maier ist in Entwicklung. Beschreibe die Organisationsform.', 'Organigramm (textuell):\n\n           Geschäftsführung\n           (Herr Müller, GF)\n              |\n              Stab: Assistenz (Frau Schmidt)\n              |\n  +-----------+-----------+\n  |           |           |\nEntwicklung  Support     Vertrieb\n(Weber)     (Klein)     (Huber)\n  |           |           |\n 15 MA       5 MA        3 MA\n (inkl.\n Ausbilder\n Maier)\n\nOrganisationsform: Stab-Linien-Organisation.\n- Linie: Geschäftsführung → Abteilungsleiter → Mitarbeiter (klare Weisungswege).\n- Stab: Assistenz Schmidt berät GF ohne Weisungsrecht gegenüber den Abteilungen.\n\nVorteile:\n- Klare Verantwortlichkeiten.\n- Entlastung der GF durch Assistenz.\n- Spezialisten pro Bereich (Vertrieb/Support/Entwicklung getrennt).\n\nNachteile:\n- Langsame Kommunikation bei Querschnittsaufgaben (z.B. Customer-Anforderung in Entwicklung).\n- Potenzielle Konflikte zwischen Stab (Assistenz) und Linie (Abteilungsleiter).', 8, 'ki-generated', 3, 480),

-- ===== Mehr kompakte Seeds für andere Topics =====
('nutzwertanalyse', 'blurt', 'Schreibe wie eine Nutzwertanalyse erstellt wird: Kriterien definieren, gewichten (summe 100 %), Alternativen bewerten (Skala z.B. 1-5), gewichtete Werte summieren, höchste Gesamtpunktzahl gewinnt. Beispiel: Cloud vs On-Prem.', 'Nutzwertanalyse in 5 Schritten:\n\n1. Kriterien definieren (alle relevanten Aspekte, z.B. Kosten, Sicherheit, Skalierbarkeit, Wartungsaufwand, Verfügbarkeit, Compliance).\n2. Kriterien GEWICHTEN (Summe 100 % oder 100 Punkte). Höhere Gewichtung = wichtiger für Entscheidung.\n3. Alternativen identifizieren (z.B. AWS Cloud, On-Premise, Hybrid).\n4. Jede Alternative pro Kriterium BEWERTEN (Skala 1-5 oder 1-10).\n5. Punktzahl = Gewichtung × Bewertung pro Kriterium. Summe pro Alternative. Höchste Summe gewinnt.\n\nBeispiel: Cloud vs On-Premise für 100-Mitarbeiter-IT-Unternehmen\n\n| Kriterium          | Gew. | AWS (1-5) | Punkt | On-Prem (1-5) | Punkt |\n|--------------------|------|-----------|-------|---------------|-------|\n| Kosten 3 Jahre     | 25   | 3         | 75    | 4             | 100   |\n| Skalierbarkeit     | 20   | 5         | 100   | 2             | 40    |\n| Wartungsaufwand    | 15   | 5         | 75    | 2             | 30    |\n| Verfügbarkeit      | 15   | 5         | 75    | 3             | 45    |\n| Datenschutz/DSGVO  | 15   | 3         | 45    | 5             | 75    |\n| Performance        | 10   | 4         | 40    | 5             | 50    |\n| SUMME              | 100  |           | 410   |               | 340   |\n\n→ AWS gewinnt mit 410 vs. 340.\n\nInterpretation: Cloud ist für dieses Unternehmen insgesamt besser, wobei On-Prem bei Kosten und Datenschutz punktet. Entscheider sollten Kriterien-Gewichtung kritisch prüfen.', 10, 'ki-generated', 3, 480),
('nutzwertanalyse', 'application', 'Erstelle eine Nutzwertanalyse für die Entscheidung zwischen 3 E-Mail-Lösungen: Microsoft 365 Exchange Online, Google Workspace, Self-hosted (Zimbra). Mindestens 5 Kriterien.', 'Nutzwertanalyse E-Mail-Systeme (5 Kriterien, Skala 1-5):\n\n| Kriterium           | Gewichtung | MS 365 | Pkt | Google | Pkt | Zimbra | Pkt |\n|---------------------|:----------:|:------:|:---:|:------:|:---:|:------:|:---:|\n| Kosten 3 Jahre      | 25 %       | 3      | 75  | 3      | 75  | 5      | 125 |\n| DSGVO-Konformität   | 25 %       | 4      | 100 | 3      | 75  | 5      | 125 |\n| Integration Office  | 20 %       | 5      | 100 | 4      | 80  | 2      | 40  |\n| Administrationsauwand| 15 %      | 4      | 60  | 5      | 75  | 2      | 30  |\n| Mobile Features     | 15 %       | 5      | 75  | 5      | 75  | 3      | 45  |\n| SUMME               | 100 %      |        | 410 |        | 380 |        | 365 |\n\n→ Microsoft 365 gewinnt (410).\n\nBegründung:\n- MS 365 punktet bei Office-Integration und Mobile (Outlook, Teams).\n- Zimbra hat Kostenvorteil + volle DSGVO-Kontrolle (EU-Server, eigenes Hosting), aber hoher Adminaufwand.\n- Google fällt bei DSGVO ab (US-Cloud) und Office-Integration.\n\nEntscheidungshilfe: Bei sehr kleinem Budget + IT-Know-how → Zimbra. Bei Office-zentriertem Unternehmen → MS 365. Bei Startup-freundlicher Umgebung → Google.', 10, 'ki-generated', 4, 540),

-- ===== IoT/CPS =====
('iot-cps', 'blurt', 'Schreibe alles was du über IoT und CPS weißt: Definitionen, Sensoren vs Aktoren, Edge vs Cloud Computing, typische Protokolle (MQTT, CoAP), Anwendungsfälle Industrie 4.0.', 'IoT (Internet of Things): vernetzte physische Geräte die Daten sammeln + austauschen übers Internet. Smarte Geräte mit eigener IP-Adresse oder Gateway-Anbindung.\n\nCPS (Cyber-Physical Systems): Systeme in denen physische Prozesse durch Computer-Steuerung überwacht/kontrolliert werden. IoT ist Teilmenge davon — CPS ist umfassender (inkl. Regelungstechnik, Feedback-Loops).\n\nKomponenten:\n- Sensoren: erfassen physische Größen (Temperatur, Druck, Helligkeit, Bewegung, Position, Feuchte). Wandeln analog → digital.\n- Aktoren: setzen digitale Signale in physische Aktionen um (Motor, Ventil, LED, Pumpe, Relais).\n- Controller (Mikrocontroller / Edge-Gateway): verarbeitet Daten, steuert Aktoren.\n\nEdge vs Cloud:\n- Edge Computing: Datenverarbeitung NAHE an der Datenquelle (Gateway, Sensor selbst). Vorteile: niedrige Latenz, weniger Bandbreite, Datenschutz.\n- Cloud: zentrale Verarbeitung, Speicherung, Analyse. Vorteile: Skalierbarkeit, ML-Modelle.\n- Hybrid (Fog Computing): Kombination — Vorverarbeitung Edge, tiefe Analyse Cloud.\n\nProtokolle:\n- MQTT (Message Queuing Telemetry Transport): Publish/Subscribe, leichtgewichtig, TCP, TLS-verschlüsselbar. Standard für IoT.\n- CoAP (Constrained Application Protocol): UDP-basiert, RESTful, für sehr kleine Geräte.\n- LoRaWAN: Long Range, niedrige Bandbreite, für Landwirtschaft/Smart City.\n- Zigbee / Z-Wave: Smart Home.\n- HTTP/HTTPS: weiter verbreitet, aber "schwer" für kleine Geräte.\n\nAnwendungsfälle:\n- Smart Home: Licht, Heizung, Schloss.\n- Smart City: Parkplatzsensoren, Umweltmonitoring.\n- Industrie 4.0: Maschinen-Predictive-Maintenance, OEE-Tracking.\n- Wearables: Fitness-Tracker, Gesundheit.\n- Agriculture: Bodenfeuchte-Sensoren, automatische Bewässerung.', 14, 'ki-generated', 4, 540),
('iot-cps', 'application', 'Entwickle IoT-Konzept für Landwirt: 20 Bodenfeuchte-Sensoren verteilt, 5 Pumpen für automatische Bewässerung. Bauernhof ohne 5G-Empfang. Nenne Sensoren/Aktoren, Protokoll, Gateway-Architektur, Cloud vs Edge.', 'IoT-Konzept Bewässerung:\n\nKomponenten:\n- 20 Sensoren: Bodenfeuchte + Temperatur + EC-Wert (Düngerpegel). Batteriebetrieb, wetterfest.\n- 5 Aktoren: 12-V-Magnetventile pro Feldabschnitt, angeschlossen an Bewässerungspumpen.\n- 1 Edge-Gateway: Raspberry Pi 4 oder Industrie-PC, im Hofgebäude mit Internet.\n\nProtokoll-Wahl:\n- Sensoren → Gateway: LoRaWAN (lange Reichweite bis 15 km, batterieschonend, niedrige Bandbreite aber ausreichend für Messwerte alle 15 min).\n- Gateway → Cloud: MQTT über 4G-LTE-Router (kein 5G nötig — LTE reicht für geringes Datenvolumen).\n\nArchitektur:\n\nSensor (LoRaWAN) → LoRa-Gateway (am Hofgebäude) → Edge-PC → MQTT-Broker (cloud / on-prem)\n                                                    ↓\n                                         Regel-Engine (Node-RED)\n                                                    ↓\n                                       Aktor-Steuerung (MQTT publish)\n                                                    ↓\n                                     5 Magnetventile via Relais-Board\n\nEdge vs Cloud:\n- EDGE (Hof-PC macht): Echtzeit-Entscheidungen — Bei Bodenfeuchte < 30 % Feld A → Ventil A 10 Min öffnen. Funktioniert OHNE Internet.\n- CLOUD: Langzeit-Analyse, Dashboards, Alerting, Historie. Wird asynchron synchronisiert.\n\nBegründung:\n- LoRaWAN: Reichweite reicht für 20 Sensoren auf 5-10 ha.\n- Edge-Logik: Bewässerung muss auch bei Internet-Ausfall funktionieren (Ernte-kritisch).\n- Cloud: Bauer sieht von überall Zustand, kann remote eingreifen.\n\nBudget: ~ 3.000 € Hardware + 10 €/Monat LTE + Cloud (falls SaaS: 50-100 €/Monat).', 10, 'ki-generated', 5, 720),

-- ===== ER-MODELL =====
('er-modell', 'blurt', 'Schreibe alles was du über das ER-Modell weißt: Entitäten, Attribute, Beziehungen, Kardinalitäten (1:1, 1:n, n:m), Umwandlung in Relationenmodell, Normalisierung.', 'ER-Modell (Entity-Relationship): konzeptionelles Datenbank-Design.\n\nBausteine:\n- Entität (Entity): Objekt / Ding (Kunde, Produkt, Bestellung). Rechteck.\n- Attribut: Eigenschaft einer Entität (Name, Preis, Datum). Oval.\n- Primärschlüssel (PK): eindeutiges Attribut (Unterstrichen).\n- Beziehung (Relationship): Verbindung zwischen Entitäten (Raute).\n\nKardinalitäten:\n- 1:1 — jede Entität A hat genau eine Entität B (Person ↔ Reisepass).\n- 1:n — ein A hat viele B (Kunde hat viele Bestellungen).\n- n:m — viele A haben viele B (Studenten hören Vorlesungen). WICHTIG: n:m muss in Relationenmodell AUFGELÖST werden durch Zwischentabelle.\n\nUmwandlung ER → Relationenmodell:\n1. Jede Entität → Tabelle.\n2. PK bleibt PK.\n3. 1:n → Fremdschlüssel auf "n"-Seite.\n4. n:m → eigene Zwischentabelle mit zwei FKs.\n\nBeispiel:\nKunde(KundenID, Name, Email)\nBestellung(BestellID, KundenID_FK, Datum) ← 1:n\nProdukt(ProduktID, Bezeichnung, Preis)\nBestellposition(BestellID_FK, ProduktID_FK, Menge) ← n:m (Bestellung ↔ Produkt)\n\nNormalisierung:\n- 1. NF: atomare Werte.\n- 2. NF: 1. NF + keine partielle Abhängigkeit vom PK.\n- 3. NF: 2. NF + keine transitive Abhängigkeit.\nAnomalien ohne Normalisierung: Update- / Einfüge- / Löschanomalie.', 13, 'ki-generated', 4, 540),
('er-modell', 'application', 'Überführe ER-Modell "Wechselrichter (n) — versorgt — (m) Strang" in Relationenmodell. Attribute: Wechselrichter(Typ, Seriennummer, Beschaffungsdatum, Garantie); Strang(Modulleistung, Anzahl_Module); Beziehung "versorgt" hat Attribute (Beginn, Ende). Kennzeichne PK/FK.', 'Relationenmodell (n:m → Auflösung durch Zwischentabelle):\n\nWR (WR_ID, Typ, Seriennummer, Beschaffungsdatum, Garantie)\n  PK: WR_ID\n\nWR_Einsatz (Einsatz_ID, WR_ID_FK, Strang_ID_FK, Beginn, Ende)\n  PK: Einsatz_ID\n  FK: WR_ID_FK → WR(WR_ID)\n  FK: Strang_ID_FK → Strang(Strang_ID)\n\nStrang (Strang_ID, Modulleistung, Anzahl_Module)\n  PK: Strang_ID\n\nErklärung:\n- WR und Strang bekommen eigene IDs als PK.\n- Die n:m-Beziehung wird durch Zwischentabelle WR_Einsatz aufgelöst.\n- WR_Einsatz hat eigene Einsatz_ID als PK (alternativ Composite-Key WR_ID + Strang_ID + Beginn).\n- Beziehungsattribute (Beginn, Ende) wandern in die Zwischentabelle — sie beschreiben DEN EINSATZ, nicht den WR oder Strang alleine.\n- Die Fremdschlüssel stellen die Verknüpfung sicher.\n\nSQL:\n\nCREATE TABLE WR (\n  WR_ID SERIAL PRIMARY KEY,\n  Typ VARCHAR(100) NOT NULL,\n  Seriennummer VARCHAR(50) UNIQUE NOT NULL,\n  Beschaffungsdatum DATE,\n  Garantiedauer INT\n);\n\nCREATE TABLE Strang (\n  Strang_ID SERIAL PRIMARY KEY,\n  Modulleistung INT,\n  Anzahl_Module INT\n);\n\nCREATE TABLE WR_Einsatz (\n  Einsatz_ID SERIAL PRIMARY KEY,\n  WR_ID INT NOT NULL REFERENCES WR(WR_ID),\n  Strang_ID INT NOT NULL REFERENCES Strang(Strang_ID),\n  Beginn DATE NOT NULL,\n  Ende DATE\n);', 12, 'W2324-PB2-2.1', 4, 900),

-- ===== PROJEKTMANAGEMENT =====
('projektmanagement', 'blurt', 'Schreibe alles was du über Projektmanagement weißt: Projekt-Merkmale, Phasen (Wasserfall), agile Methoden (Scrum, Kanban), Risikomanagement, Projektabschluss.', 'Projekt-Merkmale (vs. "normales Arbeiten"):\n- Einmaligkeit (nicht Routine).\n- Zeitlich begrenzt (Anfang + Ende).\n- Definiertes Ziel.\n- Ressourcenbegrenzt (Budget, Team).\n- Komplexität.\n- Organisation (Projektteam unabhängig vom Tagesgeschäft).\n\nWasserfall-Phasen:\n1. Initiierung (Auftrag, Grobziele, Machbarkeit).\n2. Planung (Arbeitspakete, Meilensteine, Ressourcen, Budget).\n3. Durchführung (Umsetzung, Monitoring).\n4. Abschluss (Abnahme, Dokumentation, Lessons Learned).\n\nAgile (iterativ statt linear):\n\nSCRUM:\n- Rollen: Product Owner (Vision, Backlog), Scrum Master (moderiert, schützt Team), Team (crossfunktional, 5-9 Personen).\n- Artefakte: Product Backlog (Gesamt), Sprint Backlog (aktueller Sprint), Increment (lauffähiges Ergebnis).\n- Events: Sprint Planning (Anfang), Daily Standup (15 min täglich), Sprint Review (Demo), Retrospective (Verbesserung).\n- Sprint: 1-4 Wochen, fest, liefert Inkrement.\n\nKANBAN:\n- Visualisierung via Board (To Do / Doing / Done).\n- WIP-Limits (Work In Progress limitieren) um Engpässe zu sehen.\n- Pull-System (Team zieht sich Arbeit, keine Zuweisung).\n- Kontinuierlich (keine Sprint-Grenzen).\n\nWasserfall vs Agil: Wasserfall bei stabilen Anforderungen (Bauprojekt), Agil bei Veränderlichkeit (Software).\n\nRisikomanagement: Risiken identifizieren, bewerten (Eintritt × Schaden), priorisieren, Maßnahmen planen (Vermeidung, Reduktion, Transfer/Versicherung, Akzeptanz), Monitoring.', 12, 'ki-generated', 4, 540),
('projektmanagement', 'application', 'Du leitest ein Projekt: Einführung einer neuen CRM-Software für 100-MA-Unternehmen. Welche Methode (Wasserfall oder Scrum) wählst du und warum? Beschreibe 3 Projektphasen und nenne 3 typische Risiken + Gegenmaßnahmen.', 'Methodenwahl: SCRUM oder Hybrid (Wasserfall für Rahmen + Scrum für Software-Anpassung).\n\nBegründung:\n- CRM-Einführung ist komplex, Anforderungen entwickeln sich beim Anwender-Feedback.\n- User-Interaktion ist wichtig — Scrum-Reviews mit Anwendern alle 2 Wochen.\n- Reine Wasserfall: Risiko dass nach 6 Monaten ein System geliefert wird, das Anwender nicht nutzen wollen.\n\n3 Projektphasen:\n\n1. Initiierung (4 Wochen):\n- Anforderungsanalyse (Vertrieb, Support interviewen).\n- Ausgangszustand erfassen (alte Excel-Sheets, evtl. Altsystem).\n- Budget-Festlegung (~50.000 €), Team-Aufstellung.\n- Entscheidung: SaaS-CRM (Salesforce, HubSpot) vs Open-Source (SuiteCRM).\n- Stakeholder: Geschäftsführung, Vertriebsleiter, IT.\n\n2. Umsetzung (12 Wochen, 6 Sprints á 2 Wochen):\n- Sprint 1-2: CRM-Grundinstallation, User-Verwaltung, erste Felder.\n- Sprint 3-4: Datenmigration aus Excel, Dublettenbereinigung.\n- Sprint 5-6: Integration (E-Mail, Telefonanlage, Kalender).\n- Nach jedem Sprint: Demo mit Vertriebsleiter, Feedback.\n- Daily Standups (15 Min).\n\n3. Abschluss (4 Wochen):\n- Anwender-Schulungen (pro Abteilung 1 Tag).\n- Go-Live mit Parallel-Betrieb (2 Wochen).\n- Abschaltung Altsystem.\n- Abnahme durch GF.\n- Lessons Learned, Dokumentation.\n\n3 Risiken + Gegenmaßnahmen:\n\n1. RISIKO: Datenmigration fehlerhaft (Dubletten, verlorene Historie)\n   MASSNAHME: Migration in 3 Testläufen, Qualitätskontrolle via Stichproben, Rollback-Plan\n\n2. RISIKO: Anwenderakzeptanz niedrig (Vertrieb nutzt alte Excel-Sheets weiter)\n   MASSNAHME: Früh einbinden (User-Stories mit Vertrieb definieren), Schulungen, Champions pro Abteilung, nach Go-Live-Support (Hotline 2 Wochen)\n\n3. RISIKO: Budget-Überschreitung durch Custom-Entwicklung\n   MASSNAHME: Feature-Priorisierung (MVP zuerst), 15 % Budget-Puffer, monatliches Budget-Review, Change Requests nur nach GF-Freigabe', 12, 'ki-generated', 5, 900)

) AS v(slug, item_type, prompt, model_answer, points, source_exam, difficulty, estimated_time_sec)
JOIN topic_lookup t ON t.slug = v.slug
ON CONFLICT DO NOTHING;
